/**
 * Reset Password Page
 * 
 * Handles password reset with token verification. Validates reset tokens
 * from email links and allows users to set a new password with confirmation.
 */

import React, { useState, useEffect, useId } from 'react';
import { createPortal } from 'react-dom';
import { useTranslation } from 'react-i18next';
import { useNavigate, useLocation, useSearchParams } from 'react-router-dom';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { useTheme } from '@/app/providers/ThemeContext.jsx';
import { authService } from '@/features/auth/services/coreAuthService.js';
import { createResetPasswordSchema } from '@/shared/utils/validation/authSchemas.js';
import { mapFieldErrors } from '@/shared/utils/validation/helpers.js';
import { LoadingSpinner, LanguageSelector, PasswordRequirements } from '@/shared/components';
import { apiRequest } from '@/shared/services/apiClient.js';
import logger from '@/shared/utils/logger.js';
import '/styles/index.css';
import logoDark from '@/assets/images/logo-dark.png';
import logoLight from '@/assets/images/logo-light.png';

const styles = {
  container: {
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    minHeight: '100vh',
    backgroundColor: '#f5f7fa',
    padding: '20px'
  },
  formContainer: {
    width: '100%',
    maxWidth: '400px',
    padding: '40px',
    backgroundColor: 'white',
    borderRadius: '8px',
    boxShadow: '0 4px 6px rgba(0, 0, 0, 0.1)',
    textAlign: 'center',
    position: 'relative'
  },
  logo: {
    width: '180px',
    marginBottom: '24px'
  },
  title: {
    fontSize: '24px',
    fontWeight: '600',
    color: '#1a1a1a',
    marginBottom: '8px'
  },
  subtitle: {
    fontSize: '14px',
    color: '#666',
    marginBottom: '24px'
  },
  inputGroup: {
    marginBottom: '20px',
    textAlign: 'left'
  },
  label: {
    display: 'block',
    fontSize: '14px',
    fontWeight: '500',
    color: '#333',
    marginBottom: '8px'
  },
  input: {
    width: '100%',
    padding: '12px 16px',
    fontSize: '14px',
    border: '1px solid #ddd',
    borderRadius: '6px',
    outline: 'none',
    transition: 'border-color 0.2s',
    boxSizing: 'border-box'
  },
  'input:focus': {
    borderColor: '#4a90e2',
    boxShadow: '0 0 0 2px rgba(74, 144, 226, 0.2)'
  },
  'input:disabled': {
    backgroundColor: '#f5f7fa',
    cursor: 'not-allowed'
  },
  passwordInput: {
    position: 'relative'
  },
  togglePassword: {
    position: 'absolute',
    right: '12px',
    top: '50%',
    transform: 'translateY(-50%)',
    background: 'none',
    border: 'none',
    color: '#666',
    fontSize: '12px',
    cursor: 'pointer',
    padding: '4px 8px',
    borderRadius: '4px'
  },
  'togglePassword:hover': {
    backgroundColor: '#f0f2f5'
  },
  button: {
    width: '100%',
    padding: '12px',
    fontSize: '16px',
    fontWeight: '600',
    color: 'white',
    backgroundColor: '#004895',
    border: 'none',
    borderRadius: '6px',
    cursor: 'pointer',
    transition: 'background-color 0.2s',
    marginTop: '8px'
  },
  'button:hover': {
    backgroundColor: '#003d7a'
  },
  'button:disabled': {
    backgroundColor: '#a0c0e8',
    cursor: 'not-allowed'
  },
  error: {
    color: '#e74c3c',
    fontSize: '14px',
    marginBottom: '16px',
    backgroundColor: '#fdecea',
    padding: '10px',
    borderRadius: '4px',
    textAlign: 'left'
  },
  success: {
    color: '#27ae60',
    fontSize: '14px',
    marginBottom: '16px',
    backgroundColor: '#e8f5e9',
    padding: '10px',
    borderRadius: '4px',
    textAlign: 'left'
  },
  footer: {
    marginTop: '24px',
    fontSize: '14px',
    color: '#666'
  },
  link: {
    color: '#23bd00',
    textDecoration: 'none',
    fontWeight: '500',
    cursor: 'pointer',
    background: 'none',
    border: 'none',
    padding: '0',
    marginLeft: '4px'
  },
  'link:hover': {
    textDecoration: 'underline'
  }
};

const ResetPassword = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const location = useLocation();
  const { success, error: showError } = useToast();
  const { effectiveTheme } = useTheme();
  const [windowWidth, setWindowWidth] = useState(window.innerWidth);

  // Generate unique IDs for form inputs for accessibility
  const newPasswordId = useId();
  const confirmPasswordId = useId();

  useEffect(() => {
    let resizeTimer = null;
    const handleResize = () => {
      // Debounce resize events to prevent excessive re-renders
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
      resizeTimer = setTimeout(() => {
        setWindowWidth(window.innerWidth);
      }, 100);
    };

    window.addEventListener('resize', handleResize);
    return () => {
      window.removeEventListener('resize', handleResize);
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
    };
  }, []);

  // Determine which logo to use based on theme (same as sidebar)
  const logoSrc = effectiveTheme === 'dark' ? logoDark : logoLight;

  const isMobile = windowWidth <= 480;
  const isTablet = windowWidth <= 768;
  const isSmallMobile = windowWidth <= 360;


  // Get OTP, email, flow, and userId from location state
  const { otp, email, flow, userId: stateUserId } = location.state || {};

  // Get userId from sessionStorage as fallback
  const sessionUserId = sessionStorage.getItem('passwordResetUserId');

  // Use stateUserId if available, otherwise fall back to sessionUserId
  const userId = stateUserId || sessionUserId;

  // Store the userId in sessionStorage if it came from state
  useEffect(() => {
    if (stateUserId && !sessionUserId) {
      sessionStorage.setItem('passwordResetUserId', stateUserId);
    }
  }, [stateUserId, sessionUserId]);

  // Redirect if required data is missing
  useEffect(() => {
    let timer;

    const validateResetLink = () => {
      // If we're missing any required data, show error and redirect
      if (!otp || !userId || flow !== 'password-reset') {
        logger.debug('Missing required data for password reset', {
          otp: !!otp,
          userId: !!userId,
          flow: flow === 'password-reset'
        });

        // Only show error and redirect if we're not already on the forgot-password page
        if (location.pathname !== '/forgot-password') {
          showError(t('invalidOrExpiredLink', { ns: 'auth' }));
          timer = setTimeout(() => {
            navigate('/forgot-password');
          }, 2000);
        }
      } else {
        logger.debug('Password reset data is valid, showing password reset form');
      }
    };

    validateResetLink();

    return () => {
      if (timer) {clearTimeout(timer);}
    };
  }, [otp, userId, flow, navigate, location.pathname]);

  // Form state
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [formErrors, setFormErrors] = useState({});
  const [resetSuccess, setResetSuccess] = useState(false);
  const [showPassword, setShowPassword] = useState(false);

  const clearFieldError = (field) => {
    if (formErrors[field]) {
      setFormErrors((prev) => {
        const next = { ...prev };
        delete next[field];
        if (Object.keys(next).length === 1 && next._form) {
          delete next._form;
        }
        return next;
      });
    }
  };


  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');

    const schema = createResetPasswordSchema(t);
    const validation = schema.safeParse({
      password: newPassword,
      confirmPassword,
    });

    if (!validation.success) {
      const errors = mapFieldErrors(validation.error);
      setFormErrors(errors);
      const message = Object.values(errors)[0] || t('passwordValidationFailed', { ns: 'auth' });
      setError(message);
      showError(message);
      return;
    }

    const { password: validatedPassword } = validation.data;
    setFormErrors({});

    setLoading(true);

    try {
      // Make the API call - endpoint should be /api/publicauth/password/reset
      // apiClient will automatically use AUTH_BASE_URL for this endpoint
      logger.debug('Calling password reset API', { userId });
      const data = await apiRequest('/api/publicauth/password/reset', {
        method: 'POST',
        body: JSON.stringify({
          userId: userId,
          newPassword: validatedPassword
        }),
        headers: {
          'Content-Type': 'application/json',
          'X-Skip-Auth': '1'
        }
      });

      logger.debug('Password reset API response', { response: data });

      // Check if the response indicates success
      if (data.code && data.code !== '00' && data.code !== 'SUCCESS') {
        const errorMsg = data.message || t('failedToResetPassword', { ns: 'auth' });
        logger.error('Password reset failed', { error: errorMsg });
        throw new Error(errorMsg);
      }

      // Clear the stored user data after successful reset
      sessionStorage.removeItem('passwordResetUserId');
      sessionStorage.removeItem('passwordResetOTP');

      logger.debug('Password reset successful');
      setResetSuccess(true);
      success(t('passwordResetSuccessfulRedirect', { ns: 'auth' }));

      // Wait 2 seconds before redirecting to show success message
      setTimeout(() => {
        navigate('/login');
      }, 2000);
    } catch (err) {
      logger.error('Reset password error', {
        error: err,
        errorDetails: {
          message: err.message,
          stack: err.stack,
          response: err.response
        }
      });

      const errorMessage = err.message || t('failedToResetPasswordTryAgain', { ns: 'auth' });
      setError(errorMessage);
      showError(errorMessage);

      // Don't redirect immediately - let user see the error
      // Only redirect if it's an OTP/expired error after showing error for 3 seconds
      const isOtpError = errorMessage.toLowerCase().includes('otp') ||
        errorMessage.toLowerCase().includes('expired') ||
        errorMessage.toLowerCase().includes('invalid') ||
        errorMessage.toLowerCase().includes('token');

      if (isOtpError) {
        // Clear any stored OTP data since it's invalid
        sessionStorage.removeItem('passwordResetOTP');
        sessionStorage.removeItem('passwordResetUserId');

        // Wait 3 seconds before redirecting to forgot-password
        setTimeout(() => {
          navigate('/forgot-password');
        }, 3000);
      }
      // For other errors, don't redirect - let user try again
    } finally {
      setLoading(false);
    }
  };

  if (!otp || !userId) {
    return (
      <div style={styles.container}>
        <div style={{
          ...styles.formContainer,
          paddingTop: isSmallMobile ? '52px' : isMobile ? '56px' : isTablet ? '60px' : '40px'
        }}>
          {/* Language Selector */}
          <div style={{
            position: 'absolute',
            top: '20px',
            right: '20px',
            zIndex: 10,
          }}>
            <LanguageSelector />
          </div>
          <img
            src={logoSrc}
            alt="iSmartPay Logo"
            style={{
              ...styles.logo,
              transition: 'opacity var(--transition-theme)',
              opacity: 1,
              width: isSmallMobile ? '100px' : isMobile ? '120px' : isTablet ? '160px' : '180px',
              marginTop: isSmallMobile ? '2px' : isMobile ? '4px' : isTablet ? '8px' : '0',
              marginBottom: isSmallMobile ? '16px' : isMobile ? '20px' : isTablet ? '24px' : '24px'
            }}
          />
          <p>{t('invalidOrExpiredResetLink', { ns: 'auth' })}</p>
        </div>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      <div style={{
        ...styles.formContainer,
        paddingTop: isSmallMobile ? '52px' : isMobile ? '56px' : isTablet ? '60px' : '40px'
      }}>
        {/* Language Selector */}
        <div style={{
          position: 'absolute',
          top: '20px',
          right: '20px',
          zIndex: 10,
        }}>
          <LanguageSelector />
        </div>
        <img
          src={logoSrc}
          alt="iSmartPay Logo"
          style={{
            ...styles.logo,
            transition: 'opacity var(--transition-theme)',
            opacity: 1,
            width: isSmallMobile ? '100px' : isMobile ? '120px' : isTablet ? '160px' : '180px',
            marginTop: isSmallMobile ? '2px' : isMobile ? '4px' : isTablet ? '8px' : '0',
            marginBottom: isSmallMobile ? '16px' : isMobile ? '20px' : isTablet ? '24px' : '24px'
          }}
        />
        <h2 style={styles.title}>{t('resetPassword', { ns: 'auth' })}</h2>
        <p style={styles.subtitle}>{t('createNewPassword', { ns: 'auth' })}</p>

        {error && (
          <div role="alert" aria-live="assertive" aria-atomic="true" style={styles.error}>
            {error}
          </div>
        )}

        {resetSuccess ? (
          <div role="status" aria-live="polite" aria-atomic="true" style={styles.success}>
            {t('passwordResetSuccessfulRedirect', { ns: 'auth' })}
          </div>
        ) : (
          <form onSubmit={handleSubmit}>
            <div style={styles.inputGroup}>
              <label htmlFor={newPasswordId} style={styles.label}>{t('newPassword', { ns: 'auth' })}</label>
              <div style={styles.passwordInput}>
                <input
                  type={showPassword ? 'text' : 'password'}
                  id={newPasswordId}
                  value={newPassword}
                  onChange={(e) => {
                    setNewPassword(e.target.value);
                    clearFieldError('password');
                    if (error) {
                      setError('');
                    }
                  }}
                  placeholder={t('enterNewPassword', { ns: 'auth' })}
                  disabled={loading}
                  autoComplete="new-password"
                  aria-describedby={formErrors.password ? `${newPasswordId}-error` : undefined}
                  aria-invalid={!!formErrors.password}
                  style={styles.input}
                />
              </div>
              <PasswordRequirements password={newPassword} />
              {formErrors.password && (
                <p
                  id={`${newPasswordId}-error`}
                  role="alert"
                  aria-live="polite"
                  style={{ color: '#e74c3c', fontSize: '12px', marginTop: '8px' }}
                >
                  {formErrors.password}
                </p>
              )}
            </div>

            <div style={styles.inputGroup}>
              <label htmlFor={confirmPasswordId} style={styles.label}>{t('confirmNewPassword', { ns: 'auth' })}</label>
              <div style={styles.passwordInput}>
                <input
                  type={showPassword ? 'text' : 'password'}
                  id={confirmPasswordId}
                  value={confirmPassword}
                  onChange={(e) => {
                    setConfirmPassword(e.target.value);
                    clearFieldError('confirmPassword');
                    if (error) {
                      setError('');
                    }
                  }}
                  placeholder={t('enterConfirmPassword', { ns: 'auth' })}
                  disabled={loading}
                  autoComplete="new-password"
                  aria-describedby={formErrors.confirmPassword ? `${confirmPasswordId}-error` : undefined}
                  aria-invalid={!!formErrors.confirmPassword}
                  style={styles.input}
                />
                <button
                  type="button"
                  style={styles.togglePassword}
                  onClick={() => setShowPassword(!showPassword)}
                  aria-label={showPassword ? t('hidePassword', { ns: 'auth' }) : t('showPassword', { ns: 'auth' })}
                >
                  {showPassword ? t('hide', { ns: 'auth' }) : t('show', { ns: 'auth' })}
                </button>
              </div>
              {formErrors.confirmPassword && (
                <p
                  id={`${confirmPasswordId}-error`}
                  role="alert"
                  aria-live="polite"
                  style={{ color: '#e74c3c', fontSize: '12px', marginTop: '8px' }}
                >
                  {formErrors.confirmPassword}
                </p>
              )}
            </div>

            <button
              type="submit"
              disabled={loading || !newPassword || !confirmPassword || newPassword !== confirmPassword}
              style={{
                ...styles.button,
                ...(loading || !newPassword || !confirmPassword || newPassword !== confirmPassword ? styles['button:disabled'] : {})
              }}
            >
              {loading ? t('resetting', { ns: 'auth' }) : t('resetPassword', { ns: 'auth' })}
            </button>

            {/* Loading overlay popup */}
            {loading && createPortal(
              <div style={{
                position: 'fixed',
                top: 0,
                left: 0,
                right: 0,
                bottom: 0,
                width: '100vw',
                height: '100vh',
                backgroundColor: effectiveTheme === 'dark'
                  ? 'rgba(0, 0, 0, 0.85)'
                  : 'rgba(0, 0, 0, 0.5)',
                backdropFilter: 'blur(4px)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                zIndex: 99999,
                margin: 0,
                padding: 0
              }}>
                <div style={{
                  backgroundColor: effectiveTheme === 'dark'
                    ? '#141414'
                    : 'var(--card)',
                  borderRadius: '16px',
                  padding: '48px',
                  boxShadow: 'var(--shadow-xl)',
                  border: '1px solid var(--border-primary)',
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  justifyContent: 'center',
                  minWidth: '120px',
                  minHeight: '120px'
                }}>
                  <LoadingSpinner size="large" />
                </div>
              </div>,
              document.body
            )}

            <div style={styles.footer}>
              {t('rememberYourPassword', { ns: 'auth' })}{' '}
              <button
                type="button"
                style={styles.link}
                onClick={() => navigate('/login')}
              >
                {t('logIn', { ns: 'auth' })}
              </button>
            </div>
          </form>
        )}
      </div>
    </div>
  );
};

export default ResetPassword;
